"""Construcción y carga del dataset de características.Este módulo se encarga de:- leer la metadata del dataset,- recorrer las imágenes disponibles,- extraer características con el pipeline de visión,- y guardar o cargar una caché en formato parquet.La salida principal es un DataFrame con columnas como:- image_id- dx- f0, f1, f2, ..."""from __future__ import annotationsfrom pathlib import Pathfrom typing import Anyimport numpy as npimport pandas as pdfrom federated_skin.data.metadata import (    attach_image_paths,    filter_existing_images,    load_metadata,)from federated_skin.vision.pipeline import VisionPipelineclass FeatureDatasetBuilder:    """    Construye un dataset tabular de características a partir de imágenes.    Parameters    ----------    metadata_path : Path        Ruta al fichero CSV con la metadata del dataset.    images_dir : Path        Directorio que contiene las imágenes.    vision : VisionPipeline | None        Pipeline de visión encargado de procesar cada imagen y extraer        su vector de características. Si es None, se crea uno por defecto.    logger : Any | None        Logger opcional para mostrar mensajes de progreso.    """    def __init__(        self,        metadata_path: Path,        images_dir: Path,        vision: VisionPipeline | None = None,        logger: Any | None = None,    ) -> None:        self.metadata_path = metadata_path        self.images_dir = images_dir        self.vision = vision if vision is not None else VisionPipeline()        self.logger = logger    def build_or_load(self, cache_path: Path) -> pd.DataFrame:        """        Carga el dataset de características desde caché si existe.        Si no existe, lo construye desde las imágenes y lo guarda.        Parameters        ----------        cache_path : Path            Ruta del fichero parquet donde se guarda la caché.        Returns        -------        pd.DataFrame            DataFrame con las características extraídas.        """        if cache_path.exists():            if self.logger is not None:                self.logger.info("Cargando features cacheadas desde %s", cache_path)            return pd.read_parquet(cache_path)        df = self.build_dataset()        cache_path.parent.mkdir(parents=True, exist_ok=True)        df.to_parquet(cache_path, index=False)        if self.logger is not None:            self.logger.info("Features guardadas en %s", cache_path)        return df    def build_dataset(self) -> pd.DataFrame:        """        Construye el dataset de características recorriendo la metadata        y procesando las imágenes válidas.        Returns        -------        pd.DataFrame            DataFrame con columnas:            - image_id            - dx            - f0, f1, ..., fn        """        if self.logger is not None:            self.logger.info("Extrayendo features desde imágenes...")        df_meta = load_metadata(self.metadata_path)        df_meta = attach_image_paths(df_meta, self.images_dir)        df_meta = filter_existing_images(df_meta)        rows: list[dict[str, Any]] = []        for row in df_meta.itertuples():            features = self.vision.process_image_path(row.image_path)            # Se descartan imágenes que no hayan producido una segmentación            # útil o un vector informativo.            if np.allclose(features, 0.0):                continue            feature_row = {                "image_id": row.image_id,                "dx": row.dx,            }            for i, value in enumerate(features):                feature_row[f"f{i}"] = float(value)            rows.append(feature_row)        return pd.DataFrame(rows)